const body = $json.body || $json;
const jobIds = body.job_ids || body.jobIds || [];

if (!Array.isArray(jobIds) || jobIds.length < 2) {
  throw new Error('Must provide at least 2 job IDs in body.job_ids array');
}
if (jobIds.length > 10) {
  throw new Error('Maximum 10 jobs per comparison');
}

return jobIds.map(id => ({ json: { jobId: id.trim() } }));

// Gather all evaluation rows
const evalItems = $('Fetch Each Evaluation').all();
const pipelineItems = $('Fetch Pipeline Rows').all();

// Build a map of pipeline data by ID
const pipelineMap = {};
for (const p of pipelineItems) {
  const id = p.json.ID || p.json.id;
  if (id) pipelineMap[id] = p.json;
}

// Build comparison payload
const jobs = [];
for (const e of evalItems) {
  const jobId = e.json['Job ID'];
  const pipeline = pipelineMap[jobId] || {};
  let evalData = {};
  try { evalData = JSON.parse(e.json['Full Report'] || '{}'); } catch(err) {}

  jobs.push({
    job_id: jobId,
    company: pipeline.Company || evalData.company || 'Unknown',
    title: pipeline.Title || evalData.title || 'Unknown',
    url: pipeline.URL || '',
    grade: e.json.Grade,
    overall_score: parseFloat(e.json['Overall Score']) || 0,
    scores: {
      role_match: parseFloat(e.json['Role Match']) || 0,
      skills: parseFloat(e.json.Skills) || 0,
      seniority: parseFloat(e.json.Seniority) || 0,
      compensation: parseFloat(e.json.Compensation) || 0,
      geographic: parseFloat(e.json.Geographic) || 0,
      company_stage: parseFloat(e.json['Company Stage']) || 0,
      product_market: parseFloat(e.json['Product-Market']) || 0,
      growth: parseFloat(e.json.Growth) || 0,
      interview_likelihood: parseFloat(e.json['Interview Likelihood']) || 0,
      timeline: parseFloat(e.json.Timeline) || 0
    },
    archetype: e.json.Archetype,
    summary: e.json['Executive Summary'],
    cv_match: e.json['CV Match'],
    gaps: e.json.Gaps,
    confidence: e.json.Confidence || evalData.confidence || 'medium'
  });
}

if (jobs.length < 2) {
  throw new Error('Could not find evaluation data for enough jobs. Run evaluations first.');
}

return [{ json: { jobs, jobCount: jobs.length } }];

