const raw = $input.first().json.output || '{}';
let report = {};
try {
  const match = raw.match(/\{[\s\S]*\}/);
  if (match) report = JSON.parse(match[0]);
} catch(e) {
  report = { comparison_table: [], apply_order: [], strategic_notes: 'Parse error: ' + raw.substring(0, 200) };
}

const sourceData = $('Collate Comparison Data').first().json;

// Build readable summary
const topPick = report.apply_order?.[0];
const summaryLines = [
  `Compared ${sourceData.jobCount} jobs`,
  topPick ? `Top pick: ${topPick.company} (${topPick.reason})` : '',
  report.strategic_notes || ''
].filter(Boolean).join('\n');

return [{ json: { report, summaryLines, jobIds: sourceData.jobs.map(j => j.job_id).join(', '), comparisonDate: new Date().toISOString() } }];
